//! bench-hope-jar-arena — does a contiguous arena close the discharge gap?
//!
//! The shootoff left one axis to Monster: raw bulk discharge (~2×), because
//! the per-slot-Vec hybrid scatters hot slots across separate heap allocations
//! while Monster streams one contiguous 1.5 MB table. This bench tests the fix:
//! materialize E8 hot slots into ONE contiguous arena and re-measure the warm
//! read throughput against Monster and against the per-slot-Vec hybrid.
//!
//! Fair footprint: the E8 working set is 2 slots (~1.5 MB), matching both
//! Monster's table size and the proven e8_slots_in_monster_budget = 2. Keys
//! are fully consumed; median of several runs (discharge is cache-noisy).

use distributed_inference::hope_jar::HopeJar;
use distributed_inference::hope_jar_e8::HopeJarE8;
use distributed_inference::hope_jar_hybrid::{ArenaHopeJar, HybridHopeJar};
use std::hint::black_box;
use std::time::Instant;

const RUNS: usize = 7;
const PASSES: usize = 400;

fn median(mut v: Vec<f64>) -> f64 {
    v.sort_by(|a, b| a.partial_cmp(b).unwrap());
    v[v.len() / 2]
}

fn main() {
    let monster_bytes = std::fs::read("rknots/hope-jar.rknot").expect("hope-jar.rknot");
    let e8_bytes = std::fs::read("rknots/hope-jar-e8.rknot").expect("hope-jar-e8.rknot");

    // E8 working set: 2 slots (~1.5 MB, matches Monster footprint + the proven budget).
    let ws: [(u8, u8); 2] = [(3, 17), (11, 113)];

    let mut m_kps = Vec::new();
    let mut vec_kps = Vec::new();
    let mut arena_kps = Vec::new();

    for _ in 0..RUNS {
        // ── Monster: stream its 36-slot contiguous table ──
        let mut monster = HopeJar::decode_seeds(&monster_bytes).expect("monster");
        let _ = monster.discharge(0, 0); // warm
        let mut acc = 0u64;
        let mut keys = 0u64;
        let t = Instant::now();
        for _ in 0..PASSES {
            for p in 0..12u8 {
                for l in 0..3u8 {
                    let s = monster.discharge(p, l);
                    for &k in s {
                        acc ^= k;
                    }
                    keys += s.len() as u64;
                }
            }
        }
        m_kps.push(keys as f64 / t.elapsed().as_secs_f64());
        black_box(acc);

        // ── E8 per-slot-Vec hybrid: 2 hot slots in separate allocations ──
        let mut hyb = HybridHopeJar::new(HopeJarE8::decode_rknot(&e8_bytes).unwrap());
        for &(p, l) in &ws {
            let _ = hyb.discharge(p, l);
        } // materialize (warm)
        let mut acc = 0u64;
        let mut keys = 0u64;
        let t = Instant::now();
        for _ in 0..PASSES {
            for &(p, l) in &ws {
                let s = hyb.discharge(p, l);
                for &k in s {
                    acc ^= k;
                }
                keys += s.len() as u64;
            }
        }
        vec_kps.push(keys as f64 / t.elapsed().as_secs_f64());
        black_box(acc);

        // ── E8 arena: 2 hot slots packed in ONE contiguous buffer ──
        let mut arena = ArenaHopeJar::new(HopeJarE8::decode_rknot(&e8_bytes).unwrap(), 2);
        for &(p, l) in &ws {
            let _ = arena.discharge(p, l);
        } // materialize (warm)
        let mut acc = 0u64;
        let mut keys = 0u64;
        let t = Instant::now();
        for _ in 0..PASSES {
            for &(p, l) in &ws {
                let s = arena.discharge(p, l);
                for &k in s {
                    acc ^= k;
                }
                keys += s.len() as u64;
            }
        }
        arena_kps.push(keys as f64 / t.elapsed().as_secs_f64());
        black_box(acc);
    }

    let m = median(m_kps) / 1e6;
    let v = median(vec_kps) / 1e6;
    let a = median(arena_kps) / 1e6;

    // ── large working set (16 slots ≈ 12 MB, exceeds L2): where contiguity
    //    should actually matter — arena vs per-slot Vec ──
    let big_ws: Vec<(u8, u8)> = (0..16u64)
        .map(|i| ((i % 30) as u8, ((i * 7 + 1) % 240) as u8))
        .collect();
    let mut big_vec = Vec::new();
    let mut big_arena = Vec::new();
    for _ in 0..RUNS {
        let mut hyb = HybridHopeJar::new(HopeJarE8::decode_rknot(&e8_bytes).unwrap());
        for &(p, l) in &big_ws {
            let _ = hyb.discharge(p, l);
        }
        let (mut acc, mut keys) = (0u64, 0u64);
        let t = Instant::now();
        for _ in 0..(PASSES / 8) {
            for &(p, l) in &big_ws {
                let s = hyb.discharge(p, l);
                for &k in s {
                    acc ^= k;
                }
                keys += s.len() as u64;
            }
        }
        big_vec.push(keys as f64 / t.elapsed().as_secs_f64());
        black_box(acc);

        let mut arena = ArenaHopeJar::new(HopeJarE8::decode_rknot(&e8_bytes).unwrap(), 16);
        for &(p, l) in &big_ws {
            let _ = arena.discharge(p, l);
        }
        let (mut acc, mut keys) = (0u64, 0u64);
        let t = Instant::now();
        for _ in 0..(PASSES / 8) {
            for &(p, l) in &big_ws {
                let s = arena.discharge(p, l);
                for &k in s {
                    acc ^= k;
                }
                keys += s.len() as u64;
            }
        }
        big_arena.push(keys as f64 / t.elapsed().as_secs_f64());
        black_box(acc);
    }
    let bv = median(big_vec) / 1e6;
    let ba = median(big_arena) / 1e6;

    println!(
        "=== ARENA shootoff — warm read throughput (release, median of {}) ===\n",
        RUNS
    );
    println!("-- small working set: 2 slots (~1.5MB, fits cache, matches Monster) --");
    println!("  Monster (contiguous 1.5MB table)   : {:>7.0} M keys/s", m);
    println!(
        "  E8 per-slot Vecs                   : {:>7.0} M keys/s   ({:.2}x Monster)",
        v,
        v / m
    );
    println!(
        "  E8 arena (contiguous)              : {:>7.0} M keys/s   ({:.2}x Monster)",
        a,
        a / m
    );
    println!();
    println!("-- large working set: 16 slots (~12MB, exceeds L2) --");
    println!(
        "  E8 per-slot Vecs                   : {:>7.0} M keys/s",
        bv
    );
    println!(
        "  E8 arena (contiguous)              : {:>7.0} M keys/s   ({:.2}x per-slot)",
        ba,
        ba / bv
    );
    println!();
    println!("verdict:");
    if v / m >= 0.97 && a / m >= 0.97 {
        println!(
            "  - cached E8 reads MATCH Monster discharge ({:.2}x / {:.2}x) — the original",
            v / m,
            a / m
        );
        println!("    '2x Monster' was regenerate-vs-read, not a real layout deficit.");
    }
    if ba >= bv * 1.05 {
        println!(
            "  - at large working sets the arena beats per-slot Vecs {:.2}x (contiguity wins).",
            ba / bv
        );
    } else {
        println!(
            "  - at large working sets arena ≈ per-slot Vecs ({:.2}x): contiguity is not",
            ba / bv
        );
        println!("    the bottleneck at this scale; both are memory-bandwidth bound.");
    }
}
